external_knowledge:
- 'captains of the high-seas sailing' refers to the hosts of the listings;
- 'bustling ports' and 'vibrant cities' refer to the cities where the listings are located;
- 'bustling harbors' refers to the listings themselves;
- 'more than twenty explorers for a tale to tell' translates to listings having more than twenty reviews;
- 'the number of tales they've collected' refers to the number of reviews;
- 'from the grandest storyteller to the less experienced' means ordering by the number of reviews in descending order.

sql:
SELECT host_name, email, total_bookings
FROM hosts
WHERE total_bookings = (SELECT MAX(total_bookings) FROM hosts);

SELECT DISTINCT h.host_name
FROM hosts h
INNER JOIN listings l ON h.host_id = l.host_id;
